public void RegisterType(Type type, string schemaId)
    {
        if (_reservedIds.ContainsValue(schemaId))
        {
            var conflictingType = _reservedIds.First(entry => entry.Value == schemaId).Key;

            throw new InvalidOperationException(
                $"Can't use schemaId \"${schemaId}\" for type \"${type}\". " +
                $"The same schemaId is already used for type \"${conflictingType}\"");
        }

        _reservedIds.Add(type, schemaId);
    }

public virtual string BuildMessage(string messageTemplate) {
	return KeyRegex().Replace(messageTemplate, m =>	{
		var key = m.Groups[1].Value;

		if (!_placeholderValues.TryGetValue(key, out var value))
			return m.Value; // No placeholder / value

		var format = m.Groups[2].Success // Format specified?
			? $"{{0:{m.Groups[2].Value}}}"
			: null;

		return format == null
			? value?.ToString()
			: string.Format(format, value);
	});
}

public override bool IsValid(ValidationContext<T> context, TProperty value) {
	if (value == null) return true;

	var underlyingEnumType = Nullable.GetUnderlyingType(_enumType) ?? _enumType;

	if (!underlyingEnumType.IsEnum) return false;

	if (underlyingEnumType.GetCustomAttribute<FlagsAttribute>() != null) {
		return IsFlagsEnumDefined(underlyingEnumType, value);
	}

	return Enum.IsDefined(underlyingEnumType, value);
}

private static bool EvaluateFlagEnumValues(long value, Type enumType) {
	long mask = 0;
	foreach (var enumValue in Enum.GetValues(enumType)) {
		var enumValueAsInt64 = Convert.ToInt64(enumValue);
		if ((enumValueAsInt64 & value) == enumValueAsInt64) {
			mask |= enumValueAsInt64;
			if (mask == value)
				return true;
		}
	}

	return false;
}

private void UpdateLeasing(List<Service> services)
    {
        if (_leases.Count > 0)
        {
            _leases.RemoveAll(l => !services.Exists(s => s.HostAndPort == l));

            services.Where(s => !_leases.Exists(l => l == s.HostAndPort))
                .ToList()
                .ForEach(s => _leases.Add(new(s.HostAndPort, 0)));
        }
        else
        {
            services.ForEach(s => _leases.Add(new(s.HostAndPort)));
        }
    }

private static void AppendStepOut(ref DiffContext diffContext)
    {
        // If the preceding frame is a StepIn, then the StepOut cancels it out
        var previousIndex = diffContext.Edits.Count - 1;
        if (previousIndex >= 0 && diffContext.Edits.Buffer[previousIndex].Type == RenderTreeEditType.StepIn)
        {
            diffContext.Edits.RemoveLast();
        }
        else
        {
            diffContext.Edits.Append(RenderTreeEdit.StepOut());
        }
    }

public ValidationStrategy<T> IncludeRuleSets(params string[] ruleSets) {
	if (ruleSets != null && ruleSets.Length > 0) {
		if (_ruleSets == null) {
			_ruleSets = new List<string>(ruleSets);
		}
		else {
			_ruleSets.AddRange(ruleSets);
		}
	}

	return this;
}

public void Release(ServiceHostAndPort hostAndPort)
    {
        lock (SyncRoot)
        {
            var matchingLease = _leases.Find(l => l == hostAndPort);
            if (matchingLease != Lease.Null)
            {
                _ = Update(ref matchingLease, false);
            }
        }
    }

public virtual string GetStorageKey(ClientRequestIdentity identity, RateLimitOptions options)
    {
        var key = $"{options.KeyPrefix}_{identity}_{options.Rule}";
        var idBytes = Encoding.UTF8.GetBytes(key);
        var hashBytes = SHA1.HashData(idBytes);
        return Convert.ToHexString(hashBytes);
    }

private static bool RouteIsApplicableToThisRequest(Route route, string httpMethod, string upstreamHost)
    {
        var method = new HttpMethod(httpMethod.Trim());
        return (route.UpstreamHttpMethod.Count == 0 || route.UpstreamHttpMethod.Contains(method))
                &&
               (string.IsNullOrEmpty(route.UpstreamHost) || route.UpstreamHost == upstreamHost);
    }

private void SetRegion(string region, string key)
    {
        if (region.IsNotEmpty() && _regions.TryGetValue(region, out var current))
        {
            if (key.IsNotEmpty() && !current.Contains(key))
            {
                current.Add(key);
            }
        }
        else if (region.IsNotEmpty())
        {
            _regions.TryAdd(region, [key]);
        }
    }

private static string BuildFrameTypeDescriptor(RenderTreeFrame[] renderTree, int frameIndex)
    {
        var frameTypes = new List<string>();
        for (var i = 0; i <= frameIndex && i < renderTree.Length; i++)
        {
            frameTypes.Add(renderTree[i].FrameTypeField.ToString());
        }

        return string.Join(", ", frameTypes);
    }

